              "\u12A5\u1295\u12F0 \u1218\u130D\u1262\u12EB\u1363 \u1218\u1308\u1298\u1275\u1363 \u12CD\u1324\u1275 \u12A0\u1230\u1323\u1325\u1363 \u12E8\u12CD\u1324\u1275 \u12AB\u122D\u12F6\u127D\u1363 \u134B\u12ED\u1293\u1295\u1235\u1363 \u130D\u1295\u1299\u1290\u1275 \u12A5\u1293 \u12E8\u12C8\u120B\u1305 \u1218\u130D\u1262\u12EB \u12EB\u1209 \u12E8\u1275\u121D\u1205\u122D\u1275 \u1264\u1275 \u12E8\u1225\u122B \u134D\u1230\u1276\u127D\u1295 \u121B\u1235\u12AC\u12F5\u1362",
              "\u1260\u1275\u121D\u1205\u122D\u1275 \u1264\u1271 \u12E8\u1270\u1320\u12E8\u1241 \u12C8\u12F0 \u12CD\u132D \u1218\u120B\u12AA\u12EB\u12CE\u127D\u1295\u1363 \u122A\u1356\u122D\u1276\u127D\u1295\u1363 \u12F3\u123D\u1266\u122D\u12F6\u127D\u1295\u1363 \u121B\u1235\u1273\u12C8\u1242\u12EB\u12CE\u127D\u1295\u1363 \u12F0\u1228\u1230\u129E\u127D\u1295 \u12A5\u1293 \u12E8\u12A0\u1220\u122B\u122D \u121B\u1320\u1243\u1208\u12EB\u12CE\u127D\u1295 \u121B\u1218\u1295\u1328\u1275\u1362",
              "\u1208\u12F5\u130B\u134D \u1325\u12EB\u1244\u12CE\u127D\u1363 \u12E8\u1275\u130D\u1260\u122B \u1325\u12EB\u1244\u12CE\u127D\u1363 \u12E8\u121B\u1233\u12EB \u1325\u12EB\u1244\u12CE\u127D \u12A5\u1293 \u12E8\u12A0\u12AB\u12CD\u1295\u1275 \u1309\u12F3\u12EE\u127D \u121D\u120B\u123D \u1218\u1235\u1320\u1275\u1362",
